create table if not exists users (id bigint primary key auto_increment,email varchar(190) unique not null,username varchar(80) unique not null,password_hash text not null,role varchar(30) not null default 'player',email_verified_at timestamp null,email_verification_token varchar(120),remember_token varchar(120),avatar_path text,settings json not null default (json_object()),banned_until timestamp null,created_at timestamp not null default current_timestamp,updated_at timestamp not null default current_timestamp on update current_timestamp);
create table if not exists universes (id bigint primary key auto_increment,name varchar(120) not null,unique key uq_universes_name (name),speed decimal(8,2) not null default 1,fleet_speed decimal(8,2) not null default 1,research_speed decimal(8,2) not null default 1,settings json not null default (json_object()),created_at timestamp not null default current_timestamp);
create table if not exists planets (id bigint primary key auto_increment,universe_id bigint, user_id bigint,name varchar(120) not null,galaxy int not null,system int not null,slot int not null,temperature_min int default -20,temperature_max int default 60,fields_used int default 0,fields_max int default 220,metal decimal(20,3) default 500,crystal decimal(20,3) default 500,deuterium decimal(20,3) default 0,energy decimal(20,3) default 20,storage_capacity decimal(20,3) default 100000,last_resource_at timestamp not null default current_timestamp,theme varchar(80) default 'terran',unique key uq_planets_coords (universe_id,galaxy,system,slot),key idx_planets_user (user_id),constraint fk_planets_universe foreign key (universe_id) references universes(id),constraint fk_planets_user foreign key (user_id) references users(id));
create table if not exists planet_buildings (planet_id bigint,type varchar(80) not null,level int not null default 0,primary key(planet_id,type),constraint fk_planet_buildings_planet foreign key (planet_id) references planets(id) on delete cascade);
create table if not exists build_queue (id bigint primary key auto_increment,planet_id bigint,type varchar(80) not null,level int not null,finish_at timestamp not null,completed_at timestamp null,created_at timestamp default current_timestamp,key idx_build_queue_planet (planet_id),constraint fk_build_queue_planet foreign key (planet_id) references planets(id) on delete cascade);
create table if not exists researches (user_id bigint,type varchar(80) not null,level int not null default 0,primary key(user_id,type),constraint fk_researches_user foreign key (user_id) references users(id) on delete cascade);
create table if not exists research_queue (id bigint primary key auto_increment,user_id bigint,planet_id bigint,type varchar(80),level int,finish_at timestamp null,completed_at timestamp null,key idx_research_queue_user (user_id),key idx_research_queue_planet (planet_id),constraint fk_research_queue_user foreign key (user_id) references users(id),constraint fk_research_queue_planet foreign key (planet_id) references planets(id));
create table if not exists ships (planet_id bigint,type varchar(80) not null,amount bigint not null default 0,primary key(planet_id,type),constraint fk_ships_planet foreign key (planet_id) references planets(id) on delete cascade);
create table if not exists fleets (id bigint primary key auto_increment,user_id bigint,planet_id bigint,ships json not null,status varchar(30) not null default 'docked',key idx_fleets_user (user_id),key idx_fleets_planet (planet_id),constraint fk_fleets_user foreign key (user_id) references users(id),constraint fk_fleets_planet foreign key (planet_id) references planets(id));
create table if not exists fleet_movements (id bigint primary key auto_increment,user_id bigint,origin_planet_id bigint,target_galaxy int,target_system int,target_slot int,mission varchar(40),ships json not null,depart_at timestamp not null,arrive_at timestamp not null,return_at timestamp null,recalled_at timestamp null,status varchar(40) not null,key idx_fleet_arrivals (status,arrive_at),key idx_fleet_movements_user (user_id),key idx_fleet_movements_origin (origin_planet_id),constraint fk_fleet_movements_user foreign key (user_id) references users(id),constraint fk_fleet_movements_origin foreign key (origin_planet_id) references planets(id));
create table if not exists alliances (id bigint primary key auto_increment,tag varchar(12) unique not null,name varchar(120) not null,description text,created_by bigint,created_at timestamp default current_timestamp,key idx_alliances_created_by (created_by),constraint fk_alliances_created_by foreign key (created_by) references users(id));
create table if not exists alliance_members (alliance_id bigint,user_id bigint,`rank` varchar(60) default 'member',permissions json default (json_object()),joined_at timestamp default current_timestamp,primary key(alliance_id,user_id),constraint fk_alliance_members_alliance foreign key (alliance_id) references alliances(id) on delete cascade,constraint fk_alliance_members_user foreign key (user_id) references users(id) on delete cascade);
create table if not exists combats (id bigint primary key auto_increment,universe_id bigint,attacker_id bigint,defender_id bigint,coordinates varchar(40),result varchar(40),rounds json,created_at timestamp default current_timestamp,key idx_combats_universe (universe_id),key idx_combats_attacker (attacker_id),key idx_combats_defender (defender_id),constraint fk_combats_universe foreign key (universe_id) references universes(id),constraint fk_combats_attacker foreign key (attacker_id) references users(id),constraint fk_combats_defender foreign key (defender_id) references users(id));
create table if not exists battle_reports (id bigint primary key auto_increment,combat_id bigint,user_id bigint,summary json,read_at timestamp null,created_at timestamp default current_timestamp,key idx_battle_reports_combat (combat_id),key idx_battle_reports_user (user_id),constraint fk_battle_reports_combat foreign key (combat_id) references combats(id),constraint fk_battle_reports_user foreign key (user_id) references users(id));
create table if not exists marketplace_trades (id bigint primary key auto_increment,user_id bigint,offer json not null,request json not null,status varchar(30) default 'open',created_at timestamp default current_timestamp,completed_at timestamp null,key idx_market_status (status,created_at),key idx_market_user (user_id),constraint fk_marketplace_trades_user foreign key (user_id) references users(id));
create table if not exists messages (id bigint primary key auto_increment,sender_id bigint,recipient_id bigint,subject varchar(190),body text,read_at timestamp null,created_at timestamp default current_timestamp,key idx_messages_sender (sender_id),key idx_messages_recipient (recipient_id),constraint fk_messages_sender foreign key (sender_id) references users(id),constraint fk_messages_recipient foreign key (recipient_id) references users(id));
create table if not exists notifications (id bigint primary key auto_increment,user_id bigint,type varchar(80),payload json not null default (json_object()),read_at timestamp null,created_at timestamp default current_timestamp,key idx_notifications_user (user_id,read_at),constraint fk_notifications_user foreign key (user_id) references users(id));
create table if not exists achievements (id bigint primary key auto_increment,code varchar(80) unique not null,name varchar(120),description text,reward json default (json_object()));
create table if not exists user_achievements (user_id bigint,achievement_id bigint,unlocked_at timestamp default current_timestamp,primary key(user_id,achievement_id),constraint fk_user_achievements_user foreign key (user_id) references users(id),constraint fk_user_achievements_achievement foreign key (achievement_id) references achievements(id));
create table if not exists premium_transactions (id bigint primary key auto_increment,user_id bigint,kind varchar(60),amount int,metadata json default (json_object()),created_at timestamp default current_timestamp,key idx_premium_transactions_user (user_id),constraint fk_premium_transactions_user foreign key (user_id) references users(id));
